    ('criminal', 'criminal-code', 'საქმეში დადგენილია შემდეგი გარემოება: ქმედება, რომელიც არ შეიცავს ამ კოდექსის 411-ე ან 412-ე მუხლით გათვალისწინებული დანაშაულის ნიშნებს, კერძოდ: ა) მაროდიორობა, ესე იგი საომარი მოქმედების დროს მოკლულის ან დაჭრილის ნივთის. საქართველოს სისხლის სამართლის კოდექსის მიხედვით, რომელი სამართლებრივი შეფასებაა სწორი?', 'easy', 'სწორი პასუხია B, რადგან საქართველოს სისხლის სამართლის კოდექსის მუხლი 413 ადგენს შესაბამისი ქმედების დანაშაულებრივობას და სანქციას.', 'საქართველოს სისხლის სამართლის კოდექსი', 'მუხლი 413', '', '2026-06-30', false, 'ქმედება ამ მუხლით ფასდება მხოლოდ მაშინ, თუ ბრალდებული თანამდებობის პირია.', 'თუ დადასტურდება მუხლში მითითებული ყველა ნიშანი, ქმედება უნდა შეფასდეს მუხლი 413-ით გათვალისწინებულ დანაშაულად.', 'ქმედება სისხლისსამართლებრივად არ ფასდება და მხოლოდ ადმინისტრაციულ პასუხისმგებლობას იწვევს.', 'ქმედება ამ მუხლით ფასდება მხოლოდ მაშინ, თუ იგი ჩადენილია არაერთგზის.', 'B'),
    ('criminal', 'criminal-code', 'პრაქტიკულ საქმეში მხარემ განაცხადა, რომ შემდეგი წესი უნდა გამოიყენოს: ეთხოვოს საქართველოს პრეზიდენტს, 1999 წლის 7 სექტემბრამდე საქართველოს პარლამენტს განსახილველად წარუდგინოს კანონპროექტი „ნარკოტიკულ და ფსიქოტროპულ ნივთიერებათა შესახებ“. საქართველოს სისხლის სამართლის კოდექსის შესაბამისად, რომელი სამართლებრივი შეფასებაა სწორი?', 'easy', 'სწორი პასუხია D, რადგან საქართველოს სისხლის სამართლის კოდექსის მუხლი 414 ადგენს სწორედ ამ სამართლებრივ წესს.', 'საქართველოს სისხლის სამართლის კოდექსი', 'მუხლი 414', '', '2026-06-30', false, 'ეს მიდგომა გამოიყენება მხოლოდ სასამართლოს სპეციალური ნებართვის შემთხვევაში.', 'ეს მიდგომა არ გამოიყენება სისხლის სამართალში და მხოლოდ სამოქალაქო დავას ეხება.', 'ეს მიდგომა მოქმედებს მხოლოდ მაშინ, თუ ბრალდებული წერილობით დაეთანხმება.', 'მითითებული მიდგომა სწორია; ამ წესს ადგენს საქართველოს სისხლის სამართლის კოდექსის მუხლი 414.', 'D'),
    ('criminal', 'criminal-code', 'პრაქტიკულ საქმეში მხარემ განაცხადა, რომ შემდეგი წესი უნდა გამოიყენოს: ეს კოდექსი, გარდა 44-ე და 47-ე მუხლებისა და XXXIII თავისა – ფსიქოტროპული ნივთიერებისა და მისი ანალოგის მიმართ, ამოქმედდეს 2000 წლის 1 ივნისიდან. საქართველოს სისხლის სამართლის კოდექსის შესაბამისად, რომელი სამართლებრივი შეფასებაა სწორი?', 'easy', 'სწორი პასუხია B, რადგან საქართველოს სისხლის სამართლის კოდექსის მუხლი 415 ადგენს სწორედ ამ სამართლებრივ წესს.', 'საქართველოს სისხლის სამართლის კოდექსი', 'მუხლი 415', '', '2026-06-30', false, 'ეს მიდგომა მოქმედებს მხოლოდ მაშინ, თუ ბრალდებული წერილობით დაეთანხმება.', 'მითითებული მიდგომა სწორია; ამ წესს ადგენს საქართველოს სისხლის სამართლის კოდექსის მუხლი 415.', 'ეს მიდგომა გამოიყენება მხოლოდ სასამართლოს სპეციალური ნებართვის შემთხვევაში.', 'ეს მიდგომა არ გამოიყენება სისხლის სამართალში და მხოლოდ სამოქალაქო დავას ეხება.', 'B')
  ) as s(category_slug, subcategory_slug, text, difficulty, explanation, law_name, law_article, source_url, law_version_date, is_prime, option_a, option_b, option_c, option_d, correct_option)
  loop
    select id into v_article_id
    from public.law_articles
    where law_id = v_law_id and article_number = r.law_article;

    insert into public.questions(
      category_id, subcategory_id, text, difficulty, explanation, law_name, law_article,
      source_url, law_version_date, needs_review, is_prime, is_published, verified_at,
      law_id, primary_law_article_id
    )
    values (
      v_category_id, v_subcategory_id, r.text, r.difficulty::public.difficulty, r.explanation,
      r.law_name, r.law_article, nullif(r.source_url,''), r.law_version_date::date,
      false, r.is_prime, true, now(), v_law_id, v_article_id
    )
    returning id into v_question_id;

    insert into public.question_options(question_id, option_text, is_correct, sort_order) values
    (v_question_id, r.option_a, r.correct_option='A', 1),
    (v_question_id, r.option_b, r.correct_option='B', 2),
    (v_question_id, r.option_c, r.correct_option='C', 3),
    (v_question_id, r.option_d, r.correct_option='D', 4);

    insert into public.question_law_articles(question_id, law_article_id, is_primary)
    values (v_question_id, v_article_id, true)
    on conflict (question_id, law_article_id) do update set is_primary=true;
  end loop;
end $$;
